import{_ as t,o as r,c as o,a2 as i}from"./chunks/framework.VxKNwi4m.js";const u=JSON.parse('{"title":"업무실행내역 (Activity)","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/activity.md","filePath":"work-manage/activity.md","lastUpdated":1784132068000}'),e={name:"work-manage/activity.md"};function n(l,a,s,h,g,d){return r(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="업무실행내역-activity" tabindex="-1">업무실행내역 (Activity) <a class="header-anchor" href="#업무실행내역-activity" aria-label="Permalink to &quot;업무실행내역 (Activity)&quot;">​</a></h1><p><strong>업무실행내역</strong> 페이지는 프로젝트 내에서 발생한 모든 변경 사항과 활동 내역을 시간 순으로 확인할 수 있는 &#39;프로젝트 히스토리&#39; 화면입니다. 누가, 언제, 어떤 업무를 수행했는지 한눈에 파악할 수 있으며, 각 활동의 핵심 내용을 요약하여 제공합니다.</p><hr><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>업무실행내역은 프로젝트의 살아있는 기록부와 같습니다. 업무의 생성 및 상태 변경, 의견 작성뿐만 아니라 회의록, 공지사항, 문서, 게시글의 업데이트 내역까지 날짜별로 정리되어 표시됩니다. 기본적으로 최근 10일간의 기록을 먼저 보여주며, 각 항목의 상세 페이지로 들어가지 않고도 주요 내용을 미리 확인할 수 있는 <strong>컨텐츠 요약 기능</strong>을 제공합니다.</p><hr><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📅-기간별-기록-조회-및-이동" tabindex="-1">📅 기간별 기록 조회 및 이동 <a class="header-anchor" href="#📅-기간별-기록-조회-및-이동" aria-label="Permalink to &quot;📅 기간별 기록 조회 및 이동&quot;">​</a></h3><ul><li><strong>기간 확인</strong>: 목록 상단에 표시된 날짜 범위를 통해 현재 보고 있는 기록의 기간을 확인할 수 있습니다.</li><li><strong>날짜 이동</strong>: 목록 하단의 <strong>[« 뒤로]</strong> 버튼은 10일 이전의 기록으로, <strong>[다음 »]</strong> 버튼은 10일 이후의 기록으로 이동합니다.</li><li><strong>특정 날짜 지정</strong>: 우측 설정창의 &#39;10일 기록&#39; 캘린더 아이콘을 클릭하여 특정 날짜를 선택하면, 해당 날짜를 기준으로 과거 10일간의 기록을 즉시 불러옵니다.</li></ul><h3 id="👥-사용자별-활동-필터링" tabindex="-1">👥 사용자별 활동 필터링 <a class="header-anchor" href="#👥-사용자별-활동-필터링" aria-label="Permalink to &quot;👥 사용자별 활동 필터링&quot;">​</a></h3><ul><li>특정 팀원의 활동만 모아보고 싶을 때 우측 설정창의 <strong>[사용자]</strong> 필터를 사용합니다.</li><li>본인의 활동 내역만 확인하려면 목록에서 **[&lt;&lt; 나 &gt;&gt;]**를 선택하고 &#39;적용&#39; 버튼을 클릭하세요.</li></ul><h3 id="🗂️-활동-유형별-필터링-다각화된-카테고리" tabindex="-1">🗂️ 활동 유형별 필터링 (다각화된 카테고리) <a class="header-anchor" href="#🗂️-활동-유형별-필터링-다각화된-카테고리" aria-label="Permalink to &quot;🗂️ 활동 유형별 필터링 (다각화된 카테고리)&quot;">​</a></h3><p>보고 싶은 활동의 종류만 선택하여 목록을 간소화할 수 있습니다. 각 유형별로 다음과 같은 정보를 제공합니다.</p><ul><li><strong>업무</strong>: 업무 생성, 상태 변경 등의 활동과 함께 해당 업무의 <strong>설명 요약</strong>을 표시합니다.</li><li><strong>의견</strong>: 업무에 달린 <strong>댓글 내용</strong>을 직접 확인할 수 있습니다.</li><li><strong>회의록</strong>: 새 회의록 등록 시 <strong>회의 의제(Agenda)</strong> 요약을 함께 표시합니다.</li><li><strong>공지</strong>: 공지사항의 <strong>요약(Summary)</strong> 또는 내용을 확인할 수 있습니다.</li><li><strong>문서</strong>: 업로드되거나 수정된 <strong>문서의 본문 요약</strong>을 표시합니다.</li><li><strong>게시물</strong>: 게시판에 작성된 <strong>게시글의 본문 요약</strong>을 표시합니다.</li></ul><h3 id="🌲-하위-프로젝트-포함" tabindex="-1">🌲 하위 프로젝트 포함 <a class="header-anchor" href="#🌲-하위-프로젝트-포함" aria-label="Permalink to &quot;🌲 하위 프로젝트 포함&quot;">​</a></h3><ul><li>현재 프로젝트에 포함된 하위 프로젝트들의 활동까지 함께 보고 싶다면 <strong>[하위 프로젝트]</strong> 체크박스를 선택하세요. 대규모 프로젝트의 전체 흐름을 파악할 때 유용합니다.</li></ul><hr><h2 id="_3-이용-팁" tabindex="-1">3. 이용 팁 <a class="header-anchor" href="#_3-이용-팁" aria-label="Permalink to &quot;3. 이용 팁&quot;">​</a></h2><h3 id="🔍-일관성-있는-컨텐츠-미리보기" tabindex="-1">🔍 일관성 있는 컨텐츠 미리보기 <a class="header-anchor" href="#🔍-일관성-있는-컨텐츠-미리보기" aria-label="Permalink to &quot;🔍 일관성 있는 컨텐츠 미리보기&quot;">​</a></h3><p>최근 업데이트를 통해 모든 활동 유형(업무, 의견, 회의, 공지, 문서, 게시물)에서 컨텐츠 요약이 일관성 있게 제공됩니다. 이태릭체로 표시되는 요약 문구를 통해 상세 페이지 이동 없이도 활동의 맥락을 빠르게 파악할 수 있습니다.</p><h3 id="🔗-상세-내용-바로가기" tabindex="-1">🔗 상세 내용 바로가기 <a class="header-anchor" href="#🔗-상세-내용-바로가기" aria-label="Permalink to &quot;🔗 상세 내용 바로가기&quot;">​</a></h3><ul><li>활동 기록에 표시된 제목(업무 번호, 회의 제목, 문서명 등)을 클릭하면 해당 항목의 상세 페이지로 즉시 이동합니다.</li><li>사용자 이름을 클릭하면 해당 사용자의 프로필 및 상세 정보 페이지로 이동합니다.</li></ul><h3 id="📈-히스토리-추적-및-투명성" tabindex="-1">📈 히스토리 추적 및 투명성 <a class="header-anchor" href="#📈-히스토리-추적-및-투명성" aria-label="Permalink to &quot;📈 히스토리 추적 및 투명성&quot;">​</a></h3><p>특정 업무의 상태가 변경되었거나 중요한 결정이 내려진 시점을 찾고 싶을 때 업무실행내역을 활용하세요. 모든 활동에는 작성자가 명시되므로 팀 내 커뮤니케이션의 투명성을 높여줍니다.</p>',24)])])}const _=t(e,[["render",n]]);export{u as __pageData,_ as default};
